const beginRunEffect = (
  browserWindow: BrowserWindow,
  input: StartRunInput,
  resume: boolean
): BackendEffect<{ runId: string; threadId: string }, unknown, BackendServices | CodexRunDependencyServices> =>
  Effect.gen(function*() {
    const dependencies = yield* CodexRunDependencyService;
    return yield* fromPromise(() => beginRunPromise(browserWindow, input, resume, dependencies));
  });

export const startCodexRun = (
  browserWindow: BrowserWindow,
  input: StartRunInput,
  dependencies?: CodexRunDependencies
): Promise<{ runId: string; threadId: string }> =>
  runBackendEffect(Effect.provide(beginRunEffect(browserWindow, input, false), codexRunDependencyLayer(dependencies)));

export const resumeCodexRun = (
  browserWindow: BrowserWindow,
  input: StartRunInput,
  dependencies?: CodexRunDependencies
): Promise<{ runId: string; threadId: string }> =>
  runBackendEffect(Effect.provide(beginRunEffect(browserWindow, input, true), codexRunDependencyLayer(dependencies)));

export const cancelCodexRun = async (runId: string): Promise<void> => {
  const run = activeRuns.get(runId);
  if (!run) return;
  run.abortController.abort();
  await updateTicketRunState(run.projectPath, run.ticketId, { runStatus: "cancelled" });
};

